using System.Collections.Generic;using System.Threading.Tasks;using Cysharp.Threading.Tasks;using NPCs.Enemies;using Unity.VisualScripting;using UnityEngine;namespace NPCs.States{    public class SearchState : NPCState    {        /* * * * * * * * * *         * NPC Components  *         * * * * * * * * * */        /// The primary script for enemies: <see cref="BaseEnemy">BaseEnemy</see>        private readonly BaseEnemy enemy;                        /* * * * * * * * * * *         * Search Components *         * * * * * * * * * * */        /// The entity this enemy is searching for         private Transform target => enemy.target;                /// The current path from the Start Node to the Goal Node (from Top to Bottom of the stack)        private Stack<Vector3> curPath;                /// The second location to search for a lost target         private Vector3 secondDestination;        /// The delay between marking the first and second search locations        private int searchDelay;                /// Whether the entity is searching the second search location        private bool onSecondSearch;                        // HEADER: CONSTRUCTOR        public SearchState(BaseEnemy new_enemy) : base(new_enemy) { enemy = new_enemy; }                        // HEADER: STATE METHODS        // ReSharper disable Unity.PerformanceAnalysis        public override async UniTask Enter()        {            // Create a path to the last known location of the target            curPath = AStarSearch.Search(enemy.transform, target.position);            if(curPath.IsUnityNull()){ _ = stateMachine.ChangeToState(NPCStateEnum.Idle); return;}                        // Start moving the enemy through the path            if (curPath != null) movement.SetDestination(curPath.Pop());                        // After a delay, mark the second location              await UniTask.Delay(searchDelay);            secondDestination = target.position;        }        public override async UniTask Run() {            // If the enemy is found, return to a Chase State            if (npc.TargetInSight()) { _ = stateMachine.ChangeToState(NPCStateEnum.Chasing); return; }                        // If Search execution is paused, return, otherwise do Search for Target            if (pause) return; await Search();        }        public override UniTask Exit() {return UniTask.CompletedTask;}                        // HEADER: SEARCH METHODS                // ReSharper disable Unity.PerformanceAnalysis        /// Implementation for making an Enemy follow a given path         private async Task Search()        {            // If the enemy has not yet reached the target position, move towards it            if (!movement.AtDestination()) { movement.MoveTowardsDestination(); }                        // If the enemy has reached the target position, but the path has not been fully traversed, get the next target position            else if (!NoPath()){ movement.SetDestination(curPath.Pop()); }                        // If the Stack is empty,             else            {                if (!onSecondSearch) { // If not yet searching the second location                    onSecondSearch = true;                                        // Pause Run(), and set a 5000 tick timer                     var secondPosNotFound = false;                    _ = InvokeWithPause(() => {                        secondPosNotFound = true;                    }, 5000);                    // If the timer has not expired, continue searching for a valid path to the second destination                    while (!secondPosNotFound && NoPath()) {                        curPath = AStarSearch.Search(enemy.transform, secondDestination); }                                        // If a valid path is not found, set the NPC back to idle                    if(secondPosNotFound){ _ = stateMachine.ChangeToState(NPCStateEnum.Idle); return;}                                        // Otherwise, move down the path                    movement.SetDestination(curPath.Pop());                }                                // Once both search locations have been checked, and target is not found, return to Idle State                enemy.SetAnimationTrigger("Idle");                await UniTask.Delay(searchDelay); // Delay before returning to idle state                _ = stateMachine.ChangeToState(NPCStateEnum.Idle);             }        }                // HEADER: HELPER METHODS                /// <summary> Returns true if the enemy doesn't have a path / curPath is empty </summary>        private bool NoPath() { return curPath.IsUnityNull() || curPath.Count == 0; }    }}